export const getCalculateRelationshipUrl = (familyId: string,
    params: CalculateRelationshipParams,) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {

    if (value !== undefined) {
      normalizedParams.append(key, value === null ? 'null' : value.toString())
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0 ? `/api/families/${familyId}/relationship-path?${stringifiedParams}` : `/api/families/${familyId}/relationship-path`
}

/**
 * @summary AI-calculate relationship between two members
 */
export const calculateRelationship = async (familyId: string,
    params: CalculateRelationshipParams, options?: RequestInit): Promise<RelationshipPathResult> => {

  return customFetch<RelationshipPathResult>(getCalculateRelationshipUrl(familyId,params),
  {
    ...options,
    method: 'GET'


  }
);}





